DrupalŌĆÖs BigPipe and Webform modules defer DOM updates ŌĆö relying on `load` or `domcontentloaded` is insufficient. Instead, **wait for the Webform UI to become interactive** *and* for axe to detect no new ARIA changes.

**Recommended pattern:**
```ts
import { AxeBuilder } from '@axe-core/playwright';
import { test, expect } from '@playwright/test';

const waitUntilStable = async (page: Page) => {
  // Wait until no network activity + no DOM mutation in 1s
  await page.waitForLoadState('networkidle');
  await new Promise((resolve) => setTimeout(resolve, 500));
  await page.waitForFunction(() => {
    const mutations = new Promise((r) => {
      const observer = new MutationObserver(() => {});
      observer.observe(document.body, { childList: true, subtree: true });
      setTimeout(() => {
        observer.disconnect();
        r(true);
      }, 1000);
    });
    return mutations;
  }, { timeout: 15_000 });
};

test('webform-wcag22aa', async ({ page }) => {
  await page.goto('https://agency.example.org/contact');
  await waitUntilStable(page);

  // Optional: explicitly wait for Webform to be ready
  await page.waitForSelector('[data-webform-id]', { timeout: 10_000 });

  const results = await new AxeBuilder({ page })
    .withTags(['wcag2aa', 'wcag22aa'])
    .include('form')
    .analyze();

  expect(results.violations.length).toBe(0);
});
```

**Alternative (simpler but less robust):**
```ts
