You must explicitly activate each tab *and* wait for its content to stabilize before scanning. Do not rely on `waitForLoadState()` alone ŌĆö tab content is often injected via JS without network requests.

TypeScript pattern:
```ts
import { test, expect } from '@playwright/test';
import AxeBuilder from '@axe-core/playwright';

test('All tabs in tabbed interface are accessible', async ({ page }) => {
  await page.goto('/content-with-tabs');
  await page.waitForLoadState('networkidle');

  const tabs = page.locator('.tabs button[role="tab"]');
  const tabCount = await tabs.count();
  const allViolations: AxeBuilder.AxeResults[] = [];

  for (let i = 0; i < tabCount; i++) {
    const tab = tabs.nth(i);
    const tabId = await tab.getAttribute('aria-controls');

    // Click and wait for visibility of new content
    await tab.click();
    await page.waitForSelector(`#tab-content-${tabId}`, { state: 'visible' });
    await page.waitForTimeout(300); // allow JS animations/transitions

    // Scan only the newly activated tab panel
    const results = await new AxeBuilder({ page })
      .withTags(['wcag2a', 'wcag2aa', 'wcag22aa'])
      .include(`#tab-content-${tabId}`)
      .analyze();

    allViolations.push(results);

    // Optional: attach per-tab reports for debugging
    if (results.violations.length > 0) {
      console.warn(`Tab ${i + 1} has violations:`, results.violations.map(v => v.id));
    }
  }

  // Optional: aggregate violations for final assertion
  const totalViolations = allViolations.reduce((acc, r) => acc + r.violations.length, 0);
  expect(totalViolations).toBe(0);
});
```

