Use PlaywrightŌĆÖs `locator` + `evaluate` to reconstruct a stable, human-readable path from the Axe `target` selector. HereŌĆÖs a robust helper:

```ts
import { test } from '@playwright/test';
import AxeBuilder from '@axe-core/playwright';

async function getAxeElementPath(
  page: any,
  target: string
): Promise<string> {
  const element = await page.$(target);
  if (!element) return 'Element not found';

  const path = await element.evaluate((el: Element) => {
    const parts: string[] = [];
    let current: Element | null = el;
    while (current && current.nodeType === Node.ELEMENT_NODE) {
      let selector = current.tagName.toLowerCase();
      if (current.id) {
        selector += `#${current.id}`;
      } else if (current.className && typeof current.className === 'string') {
        const classes = current.className.trim().split(/\s+/).slice(0, 2);
        if (classes.length) selector += `.${classes.join('.')}`;
      }
      parts.unshift(selector);
      current = current.parentElement;
    }
    return parts.join(' > ');
  });

  return path;
}

test('axe violations with readable paths', async ({ page }) => {
