          const readablePath = await getAxeElementPath(page, target);
          // Attach to test report for debugging
          await test.info().attach(`axe-violation`, {
            body: JSON.stringify({ target, path: readablePath, help: violation.help }, null, 2),
            contentType: 'application/json'
